const payload = $input.first().json.body ?? $input.first().json;
const customer = payload.customer ?? {};
const portalPath = payload.portalPath ?? payload.portal_path ?? (customer.portal_token ? `/ai-employees/portal/${customer.portal_token}` : null);
const publicBaseUrl = ($env.AI_EMPLOYEES_PUBLIC_BASE_URL ?? 'https://ai-employees-gamma.vercel.app').replace(/\/$/, '');
const portalUrl = portalPath?.startsWith('http') ? portalPath : portalPath ? `${publicBaseUrl}${portalPath}` : null;

return [{
  json: {
    event: payload.event ?? 'ai_employee.send_intake_link',
    source_app: payload.source_app ?? 'OBMC AI Employees',
    received_at: new Date().toISOString(),
    customer,
    portal_path: portalPath,
    portal_url: portalUrl,
    email_message: {
      to: customer.email ?? null,
      subject: 'Your OBMC AI Employees intake link',
      text: [
        `Hi ${customer.contact_name ?? customer.business_name ?? 'there'},`,
        '',
        'Your private OBMC AI Employees intake workspace is ready.',
        portalUrl ? `Complete intake here: ${portalUrl}` : 'Your intake link is being prepared by OBMC.',
        '',
        'Use this link to share services, FAQs, lead fields, appointment rules, GoHighLevel notes, and launch preferences.',
        '',
        'One Big Media Company LLC'
      ].join('\n')
    },
    sms_message: customer.phone && portalUrl ? {
      to: customer.phone,
      text: `OBMC AI Employees intake link: ${portalUrl}`
    } : null,
    ghl_task: {
      title: 'AI Employee intake link sent',
      contact_email: customer.email ?? null,
      note: portalUrl ? `Private intake link sent: ${portalUrl}` : 'Private intake link requested.',
      tags: ['OBMC AI Employees', 'Intake Link Sent']
    },
    next_step: 'send_customer_email_and_create_ghl_follow_up_task'
  }
}];
